#[tokio::test]
async fn test_filesystem_with_watch() {
    let dir = create_test_filesystem();

    let provider = FilesystemProvider::new(dir.path())
        .with_watch(true)
        .build();

    let server = ServerBuilder::new("test", "1.0")
        .resource_provider(provider)
        .build();

    // Subscribe to changes
    let mut changes = server.subscribe_resource_changes().await;

    // Modify a file
    std::fs::write(dir.path().join("config.json"), r#"{"port": 9090}"#).unwrap();

    // Should receive notification
    let notification = tokio::time::timeout(
        Duration::from_secs(1),
        changes.recv()
    ).await.unwrap().unwrap();

