SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(dirname "$SCRIPT_DIR")"
LOG_FILE="/tmp/fastmcp_filesystem_e2e_$(date +%Y%m%d_%H%M%S).log"
TEST_DIR="/tmp/fastmcp_test_files_$$"

log() {
    local level="$1"
    shift
    echo "[$(date +%H:%M:%S)] [$level] $*" | tee -a "$LOG_FILE"
}

cleanup() {
    log "INFO" "Cleaning up..."
    rm -rf "$TEST_DIR"
    [[ -n "${SERVER_PID:-}" ]] && kill "$SERVER_PID" 2>/dev/null || true
}
trap cleanup EXIT

log "INFO" "=== FastMCP FilesystemProvider E2E Test ==="
log "INFO" "Log file: $LOG_FILE"

# Create test filesystem
log "INFO" "Creating test filesystem at $TEST_DIR"
mkdir -p "$TEST_DIR/docs" "$TEST_DIR/data"
echo "# Welcome" > "$TEST_DIR/docs/readme.md"
echo "Some text content" > "$TEST_DIR/docs/guide.txt"
echo '{"key": "value"}' > "$TEST_DIR/data/config.json"
echo "secret" > "$TEST_DIR/.hidden"

# Build and start server
log "INFO" "Building filesystem provider test server..."
cargo build --example filesystem_server 2>&1 | tee -a "$LOG_FILE"

log "INFO" "Starting server with filesystem at $TEST_DIR"
./target/debug/examples/filesystem_server --root "$TEST_DIR" --prefix files &
SERVER_PID=$!
sleep 2

# Init sequence
INIT='{"jsonrpc":"2.0","id":1,"method":"initialize","params":{"protocolVersion":"2024-11-05","clientInfo":{"name":"test","version":"1.0"}}}'
INITIALIZED='{"jsonrpc":"2.0","method":"initialized"}'

# Test 1: List resources
log "INFO" "Test 1: List filesystem resources"
LIST='{"jsonrpc":"2.0","id":2,"method":"resources/list"}'

RESPONSE=$(echo -e "$INIT\n$INITIALIZED\n$LIST" | nc localhost 8080 | grep '"id":2')
log "DEBUG" "Response: $RESPONSE"

if echo "$RESPONSE" | jq -e '.result.resources[] | select(.uri | contains("readme.md"))' > /dev/null 2>&1; then
    log "INFO" "PASS: Filesystem resources listed"
else
    log "ERROR" "FAIL: Filesystem resources not found"
    exit 1
fi

# Test 2: Read a resource
log "INFO" "Test 2: Read filesystem resource"
READ='{"jsonrpc":"2.0","id":3,"method":"resources/read","params":{"uri":"file://files/docs/readme.md"}}'

RESPONSE=$(echo -e "$INIT\n$INITIALIZED\n$READ" | nc localhost 8080 | grep '"id":3')
log "DEBUG" "Response: $RESPONSE"

if echo "$RESPONSE" | jq -e '.result.contents[0].text | contains("Welcome")' > /dev/null 2>&1; then
    log "INFO" "PASS: File content read correctly"
else
    log "ERROR" "FAIL: File content not read correctly"
    exit 1
fi

# Test 3: Path traversal blocked
log "INFO" "Test 3: Path traversal prevention"
TRAVERSAL='{"jsonrpc":"2.0","id":4,"method":"resources/read","params":{"uri":"file://files/../../../etc/passwd"}}'

RESPONSE=$(echo -e "$INIT\n$INITIALIZED\n$TRAVERSAL" | nc localhost 8080 | grep '"id":4')
log "DEBUG" "Response: $RESPONSE"

if echo "$RESPONSE" | jq -e '.error' > /dev/null 2>&1; then
    log "INFO" "PASS: Path traversal blocked"
else
    log "ERROR" "FAIL: Path traversal should be blocked"
    exit 1
fi

# Test 4: Hidden files excluded
log "INFO" "Test 4: Hidden files excluded by default"
RESPONSE=$(echo -e "$INIT\n$INITIALIZED\n$LIST" | nc localhost 8080 | grep '"id":2')

if echo "$RESPONSE" | jq -e '.result.resources[] | select(.uri | contains(".hidden"))' > /dev/null 2>&1; then
    log "ERROR" "FAIL: Hidden files should be excluded"
    exit 1
else
    log "INFO" "PASS: Hidden files excluded"
fi

# Test 5: MIME type detection
log "INFO" "Test 5: MIME type detection"
READ_JSON='{"jsonrpc":"2.0","id":5,"method":"resources/read","params":{"uri":"file://files/data/config.json"}}'

RESPONSE=$(echo -e "$INIT\n$INITIALIZED\n$READ_JSON" | nc localhost 8080 | grep '"id":5')
log "DEBUG" "Response: $RESPONSE"

if echo "$RESPONSE" | jq -e '.result.contents[0].mimeType | contains("json")' > /dev/null 2>&1; then
    log "INFO" "PASS: MIME type detected correctly"
else
    log "WARN" "SKIP: MIME type may not be present"
fi

log "INFO" "=== All FilesystemProvider E2E tests passed! ==="
